    17→/// Global navigator key
    18→final navigatorKey = GlobalKey<NavigatorState>();
    19→
    20→/// Widget that handles navigation state changes
    21→class NavigationHandler extends ConsumerStatefulWidget {
    22→  final Widget child;
    23→
    24→  const NavigationHandler({
    25→    super.key,
    26→    required this.child,
    27→  });
    28→
    29→  @override
    30→  ConsumerState<NavigationHandler> createState() => _NavigationHandlerState();
    31→}
    32→
    33→class _NavigationHandlerState extends ConsumerState<NavigationHandler> {
    34→  @override
    35→  Widget build(BuildContext context) {
    36→    ref.listen<AuthNavigationState>(
    37→      authNavigationProvider,
    38→      (previous, current) {
    39→        final request = current.currentRequest;
    40→        if (request == null || request.handled) {
    41→          debugPrint('[Navigation] No pending navigation request');
    42→          return;
    43→        }
    44→
    45→        final navigatorState = navigatorKey.currentState;
    46→        if (navigatorState == null) {
    47→          debugPrint(
    48→              '[Navigation] Navigator not available, skipping navigation');
    49→          return;
    50→        }
    51→
    52→        try {
    53→          if (request.isBack) {
    54→            debugPrint('[Navigation] Handling back navigation');
    55→            if (navigatorState.canPop()) {
    56→              navigatorState.pop();
    57→            } else {
    58→              debugPrint('[Navigation] Cannot pop - no routes to pop');
    59→              return;
    60→            }
    61→          } else {
    62→            debugPrint('[Navigation] Handling navigation to ${request.route}');
    63→            navigatorState.pushNamed(
    64→              request.route,
    65→              arguments: request.arguments,
    66→            );
    67→          }
    68→
    69→          // Mark the request as handled only if navigation was successful
    70→          ref.read(authNavigationProvider.notifier).markCurrentRequestHandled();
    71→        } catch (e) {
    72→          debugPrint('[Navigation] Error during navigation: $e');
    73→          // Don't mark as handled if navigation failed
    74→        }
    75→      },
    76→    );
    77→
    78→    return widget.child;
    79→  }
    80→}
