    54→/// Parses a JWT token and returns its payload
    55→JWTPayload? _parseJwt(String token) {
    56→  try {
    57→    final parts = token.split('.');
    58→    if (parts.length != 3) return null;
    59→
    60→    final payload = json.decode(
    61→      utf8.decode(base64Url.decode(base64Url.normalize(parts[1]))),
    62→    ) as Map<String, dynamic>;
    63→
    64→    return (
    65→      sub: payload['sub'] as String,
    66→      iss: payload['iss'] as String,
    67→      exp: payload['exp'] as int,
    68→      iat: payload['iat'] as int,
    69→      email: payload['email'] as String?,
    70→      name: payload['name'] as String?,
    71→      groups:
    72→          (payload['cognito:groups'] as List<dynamic>?)?.cast<String>() ?? [],
    73→    );
    74→  } catch (e) {
    75→    return null;
    76→  }
    77→}
