    62→      // Register periodic task with constraints
    63→      await Workmanager().registerPeriodicTask(
    64→        BackgroundRefreshConfig.taskId,
    65→        BackgroundRefreshConfig.taskName,
    66→        frequency: BackgroundRefreshConfig.minRefreshInterval,
    67→        constraints: WorkManagerConstraints(
    68→          networkType: NetworkType.connected,
    69→          requiresBatteryNotLow: true,
    70→          requiresCharging: false,
    71→          requiresDeviceIdle: false,
    72→          requiresStorageNotLow: false,
    73→        ),
    74→        existingWorkPolicy: ExistingWorkPolicy.replace,
    75→        backoffPolicy: BackoffPolicy.exponential,
    76→        backoffPolicyDelay: BackgroundRefreshConfig.minRefreshInterval,
    77→      );
    78→
    79→      ref.read(tokenAuditLoggerProvider).logTokenEvent(
    80→        event: 'background_refresh_initialized',
    81→        status: 'info',
    82→        metadata: {
